GameRobot = class()

function GameRobot:ctor(config, entityId, userId)
    self.config = config
    self.entityId = entityId
    self.playerUserId = userId
    self.birthTime = os.time()
    self.keepTime = config.keepTime

    self.hp = config.hp
    self.maxHp = config.hp
    self.attack = config.attack --攻击力
end

function GameRobot:onTick(ticks)
    if os.time() - self.birthTime >= self.keepTime then
        self:onRemove()
    end
end

--被玩家攻击
function GameRobot:onAttackedByPlayer(attacker, damageType)
    attacker.lastAttackTime = os.time()

    if damageType == Define.PlayerDamageType.CloseDamage then
        self.hp = self.hp - attacker.closeDamage
    elseif damageType == Define.PlayerDamageType.RemoteDamage then
        self.hp = self.hp - attacker.remoteDamage
    end

    --HostApi.log(string.format("GameRobot:onAttackedByPlayer %d", self.hp))

    if self.hp <= 0 then
        self:onDied(attacker)
    end
end

--被怪物攻击
function GameRobot:onAttackedByMonster(attacker)
    --
end

--机器人攻击玩家
function GameRobot:onAttackPlayer(player)
    player:onAttacked(self, Define.TargetType.TargetMonster)
end

--死亡
function GameRobot:onDied(killer)
    self:DropItems()
    --self:onRemove()
    local player = PlayerManager:getPlayerByUserId(self.playerUserId)
    if player ~= nil then
        player:onRemoveRobot()
    else
        self:onRemove()
    end
end

function GameRobot:onRemove()
    --HostApi.log(string.format("GameRobot:onRemove %d", self.entityId))
    RobotManager:removeRobot(self.entityId)
    EngineWorld:removeEntity(self.entityId)
end

--掉落物品
function GameRobot:DropItems()
    local entity = EngineWorld:getEntity(self.entityId)
    for i, itemId in pairs(self.config.dropItem) do
        local item = ItemsConfig:getItemsByItemId(itemId)
        local dropsProbability = self.config.dropsProbability[i]
        local result = MathUtil:randomIntRepeat(1, 10000, 1)
        if item ~= nil and dropsProbability ~= nil and dropsProbability > result[1] then
            local position = entity:getPosition()
            local yawX = math.random(-1, 1)
            local yawZ = math.random(-1, 1)
            position.x = position.x + yawX
            position.z = position.z + yawZ
            ActorManager:createItemActor(position, item.itemId, 1, 0)
        end
    end
end

return GameRobot